{
  "name": "CorrigeAI",
  "description": "CorrigeAI is an institutional solution for grammatical and spelling correction of Word documents (.docx), aimed at structured educational content, fully preserving the formatting, pedagogical hierarchy, textual identity, and evaluation criteria of the documents."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { DocumentType, Correction } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import DocumentTypeSelector from './components/DocumentTypeSelector';
import FileUpload from './components/FileUpload';
import ProcessingView from './components/ProcessingView';
import ResultsView from './components/ResultsView';
import { extractTextFromDocx, createDocxWithComments } from './services/docxService';
import { getCorrections } from './services/geminiService';

type AppState = 'selection' | 'upload' | 'processing' | 'result' | 'error';

export default function App() {
  const [appState, setAppState] = useState<AppState>('selection');
  const [selectedDocType, setSelectedDocType] = useState<DocumentType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [resultBlob, setResultBlob] = useState<Blob | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);

  const handleDocTypeSelect = (docType: DocumentType) => {
    setSelectedDocType(docType);
    setAppState('upload');
  };

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setResultBlob(null);

    try {
      const textContent = await extractTextFromDocx(file);
      if (!textContent.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      if (!selectedDocType) {
        throw new Error("Tipo de documento não selecionado. Por favor, comece novamente.");
      }

      const corrections: Correction[] = await getCorrections(textContent, selectedDocType);

      const docxBlob = await createDocxWithComments(file, corrections);

      setResultBlob(docxBlob);
      setAppState('result');
    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, [selectedDocType]);

  const handleReset = () => {
    setAppState('selection');
    setSelectedDocType(null);
    setError(null);
    setResultBlob(null);
    setOriginalFile(null);
  };

  const renderContent = () => {
    switch (appState) {
      case 'selection':
        return <DocumentTypeSelector onSelect={handleDocTypeSelect} />;
      case 'upload':
        if (!selectedDocType) {
           handleReset();
           return null;
        }
        return <FileUpload docType={selectedDocType} onProcess={handleFileProcess} onBack={handleReset} />;
      case 'processing':
        return <ProcessingView />;
      case 'result':
        if (!resultBlob || !originalFile) {
          handleReset();
          return null;
        }
        return <ResultsView blob={resultBlob} fileName={originalFile.name} onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-white rounded-lg shadow-lg">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-dark-blue text-white rounded-md hover:bg-brand-teal transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <DocumentTypeSelector onSelect={handleDocTypeSelect} />;
    }
  };

  return (
    <div className="min-h-screen bg-brand-gray flex flex-col">
      <Header />
      <main className="flex-grow container mx-auto px-4 py-8 flex items-center justify-center">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
}

export enum DocumentType {
  EBOOK = 'E-book Educacional',
  QUESTION_BANK = 'Banco de Questões (BQ)',
  CONTEXTUALIZED_ACTIVITY = 'Atividade Contextualizada (ATC)',
  RUBRICS = 'Documento de Correção / Rubricas (DCO)',
  OTHER = 'Outro Documento DOCX Institucional',
}

export interface Correction {
  paragraphIndex: number;
  originalText: string;
  suggestedCorrection: string;
  reason: string;
}

export interface GeminiCorrectionResponse {
  corrections: Correction[];
}

import { DocumentType } from './types';

const BASE_PROMPT = `
Você é um assistente de revisão de IA especializado em documentos educacionais institucionais em português do Brasil. Sua tarefa é identificar erros gramaticais, ortográficos, de pontuação e de concordância.

REGRAS OBRIGATÓRIAS:
1.  **NÃO ALTERE O SENTIDO PEDAGÓGICO**: A sua função é estritamente de revisão textual, não de conteúdo.
2.  **PRESERVE A ESTRUTURA**: Não modifique a ordem dos parágrafos, títulos ou qualquer elemento estrutural.
3.  **SAÍDA ESTRUTURADA EM JSON**: Sua resposta DEVE ser um objeto JSON válido que corresponda ao schema fornecido.
4.  **IDENTIFICAÇÃO PRECISA**: Para cada correção, você deve fornecer o índice do parágrafo ('paragraphIndex'), o trecho exato do texto original com o erro ('originalText'), a sugestão de correção ('suggestedCorrection') e uma breve justificativa ('reason'). O 'originalText' deve ser uma correspondência exata de uma substring dentro do parágrafo para garantir a localização.
5.  **COMENTÁRIOS, NÃO SUBSTITUIÇÃO**: A política é adicionar comentários no Word, não substituir o texto silenciosamente. Sua resposta alimenta esse processo.
6.  **FOCO NA CORREÇÃO OBJETIVA**: Evite sugestões estilísticas ou de reescrita, a menos que seja para corrigir um erro claro de clareza ou ambiguidade.
`;

export const DOCUMENT_TYPE_DETAILS = {
  [DocumentType.EBOOK]: {
    icon: '📘',
    description: 'Correções gramaticais e de clareza, preservando a terminologia técnica e pedagógica.',
    prompt: `
      ${BASE_PROMPT}
      **CONTEXTO DO DOCUMENTO**: Este é um E-book Educacional. A linguagem pode ser formal e conter jargões técnicos específicos da área de estudo.
      -   **Ação**: Realize correções gramaticais, ortográficas e de pontuação.
      -   **Cuidado**: Seja extremamente cuidadoso para não alterar a terminologia técnica. Se uma palavra parecer um jargão, mesmo que não comum, presuma que está correta.
      -   **Clareza**: Aponte apenas erros que prejudiquem a clareza e a compreensão do conteúdo.
    `,
  },
  [DocumentType.QUESTION_BANK]: {
    icon: '❓',
    description: 'Correção gramatical estrita sem alterar enunciados, alternativas ou gabaritos.',
    prompt: `
      ${BASE_PROMPT}
      **CONTEXTO DO DOCUMENTO**: Este é um Banco de Questões (BQ) para avaliações. A precisão é crítica.
      -   **Ação**: Realize apenas correções gramaticais e ortográficas estritas.
      -   **NÃO FAÇA**: NÃO reescreva enunciados para "melhorar". NÃO altere o conteúdo das alternativas de múltipla escolha. NÃO modifique o gabarito ou a resposta correta. A estrutura "pergunta-resposta" é sagrada.
      -   **Exemplo**: Corrija "Qual a capital do Brasil?" para "Qual é a capital do Brasil?", mas NUNCA mude o foco da pergunta.
    `,
  },
  [DocumentType.CONTEXTUALIZED_ACTIVITY]: {
    icon: '📝',
    description: 'Correção gramatical preservando linguagem de comando e rubricas avaliativas.',
    prompt: `
      ${BASE_PROMPT}
      **CONTEXTO DO DOCUMENTO**: Esta é uma Atividade Contextualizada (ATC), que contém instruções para os alunos.
      -   **Ação**: Realize correções de gramática e concordância.
      -   **Preservar**: Mantenha a linguagem imperativa (ex: "faça", "analise", "descreva"). NÃO suavize comandos.
      -   **Rubricas**: Se houver rubricas ou critérios de avaliação, aplique correções mínimas, apenas para erros óbvios, sem alterar o critério em si.
    `,
  },
  [DocumentType.RUBRICS]: {
    icon: '📊',
    description: 'Correções mínimas em tabelas de critérios, sem reinterpretar ou alterar pesos.',
    prompt: `
      ${BASE_PROMPT}
      **CONTEXTO DO DOCUMENTO**: Este é um Documento de Correção ou Rubricas (DCO), geralmente contendo tabelas com critérios de avaliação.
      -   **Ação**: Realize APENAS correções pontuais e óbvias (erros de digitação claros).
      -   **NÃO FAÇA**: NÃO reinterprete critérios de avaliação. NÃO altere níveis de pontuação, pesos ou descrições de desempenho. A estrutura de tabelas deve ser integralmente preservada. A integridade dos critérios é a prioridade máxima.
    `,
  },
  [DocumentType.OTHER]: {
    icon: '📄',
    description: 'Correção gramatical padrão para documentos institucionais diversos.',
    prompt: `
      ${BASE_PROMPT}
      **CONTEXTO DO DOCUMENTO**: Este é um documento institucional genérico.
      -   **Ação**: Aplique as regras de correção gramatical e ortográfica padrão, conforme as diretrizes gerais. Foque em objetividade e clareza.
    `,
