import React, { useEffect, useState } from 'react';

interface ResultsViewProps {
  blob: Blob;
  fileName: string;
  onReset: () => void;
}

export default function ResultsView({ blob, fileName, onReset }: ResultsViewProps) {
  const [downloadUrl, setDownloadUrl] = useState<string | null>(null);

  useEffect(() => {
    const url = URL.createObjectURL(blob);
    setDownloadUrl(url);

    return () => {
      if (url) {
        URL.revokeObjectURL(url);
      }
    };
  }, [blob]);

  const correctedFileName = `Corrigido_${fileName}`;

  return (
    <div className="text-center p-8 bg-white rounded-lg shadow-lg w-full max-w-lg">
      <svg className="w-16 h-16 mx-auto text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
      <h2 className="text-2xl font-bold text-brand-dark-blue mt-4 mb-2">Processamento Concluído!</h2>
      <p className="text-gray-600 mb-6">
        Seu documento foi corrigido. Baixe a nova versão com os comentários e sugestões.
      </p>

      {downloadUrl && (
        <a
          href={downloadUrl}
          download={correctedFileName}
          className="inline-block px-8 py-3 bg-green-600 text-white font-bold rounded-lg shadow-md hover:bg-green-700 transition-colors"
        >
          Baixar {correctedFileName}
        </a>
      )}

      <div className="mt-8">
        <button
          onClick={onReset}
          className="text-sm text-brand-teal hover:underline"
        >
          Corrigir outro documento
        </button>
      </div>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentType, Correction, GeminiCorrectionResponse } from '../types';
import { DOCUMENT_TYPE_DETAILS } from '../constants';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const correctionSchema = {
  type: Type.OBJECT,
  properties: {
    paragraphIndex: { type: Type.INTEGER, description: "O índice do parágrafo (baseado em 0) onde o erro foi encontrado." },
    originalText: { type: Type.STRING, description: "O trecho exato do texto original que contém o erro." },
    suggestedCorrection: { type: Type.STRING, description: "A sugestão de correção para o texto." },
    reason: { type: Type.STRING, description: "Uma breve explicação do motivo da correção (ex: Ortografia, Concordância, Pontuação)." },
  },
  required: ["paragraphIndex", "originalText", "suggestedCorrection", "reason"]
};

const responseSchema = {
    type: Type.OBJECT,
    properties: {
        corrections: {
            type: Type.ARRAY,
            items: correctionSchema,
            description: "Uma lista de todas as correções encontradas no documento."
        }
    },
    required: ["corrections"]
}


export async function getCorrections(documentText: string, docType: DocumentType): Promise<Correction[]> {
  const model = "gemini-3-pro-preview"; // Using the model as per instructions
  const details = DOCUMENT_TYPE_DETAILS[docType];

  try {
    const response = await ai.models.generateContent({
        model: model,
        contents: `Analise o seguinte texto e identifique os erros de acordo com as regras fornecidas:\n\n${documentText}`,
        config: {
            systemInstruction: details.prompt,
            responseMimeType: "application/json",
            responseSchema: responseSchema,
        }
    });

    const responseText = response.text;
    if (!responseText) {
        throw new Error("A resposta da IA estava vazia.");
    }

    const parsedResponse: GeminiCorrectionResponse = JSON.parse(responseText);

    if (!parsedResponse.corrections) {
      console.warn("A resposta da IA não continha o campo 'corrections'.", parsedResponse);
      return [];
    }

    return parsedResponse.corrections;

  } catch (error) {
    console.error("Erro ao chamar a API Gemini:", error);
    if (error instanceof Error && error.message.includes('API_KEY')) {
        throw new Error("A chave de API não é válida ou está faltando. Verifique suas configurações.");
    }
    throw new Error("Não foi possível obter as correções da IA.");
  }
}

import { Correction } from '../types';

// These are global variables exposed by the scripts in index.html
declare const mammoth: any;
declare const docx: any;

/**
 * Extracts raw text content from a .docx file.
 * Each paragraph is an element in the returned string, separated by newlines.
 */
export async function extractTextFromDocx(file: File): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer });
  return result.value;
}


/**
 * Creates a new .docx file with corrections inserted as comments.
 */
export async function createDocxWithComments(originalFile: File, corrections: Correction[]): Promise<Blob> {
    const { Packer, Document, Paragraph, TextRun, CommentRangeStart, CommentRangeEnd } = docx;

    const arrayBuffer = await originalFile.arrayBuffer();
    // We need paragraphs to map corrections by index
    const textResult = await mammoth.extractRawText({ arrayBuffer });
    const originalParagraphs = textResult.value.split('\n');

    const correctionsByParagraph: Map<number, Correction[]> = new Map();
    for (const correction of corrections) {
        if (!correctionsByParagraph.has(correction.paragraphIndex)) {
            correctionsByParagraph.set(correction.paragraphIndex, []);
        }
        correctionsByParagraph.get(correction.paragraphIndex)?.push(correction);
    }

    let commentId = 0;
    const comments: any[] = [];
    const paragraphs: any[] = [];

    for (let i = 0; i < originalParagraphs.length; i++) {
        const pText = originalParagraphs[i];
        const pCorrections = correctionsByParagraph.get(i) || [];

        if (pCorrections.length === 0) {
            paragraphs.push(new Paragraph({ children: [new TextRun(pText)] }));
            continue;
        }

        // Sort corrections by their appearance in the text to handle them in order
        pCorrections.sort((a, b) => pText.indexOf(a.originalText) - pText.indexOf(b.originalText));

        const children: any[] = [];
        let lastIndex = 0;

        for (const correction of pCorrections) {
            const startIndex = pText.indexOf(correction.originalText, lastIndex);

            if (startIndex === -1) {
                // Could not find the text, maybe Gemini hallucinated or text was slightly different
                console.warn(`Could not find originalText "${correction.originalText}" in paragraph ${i}. Skipping correction.`);
                continue;
            }

            // Add text before the correction
            if (startIndex > lastIndex) {
                children.push(new TextRun(pText.substring(lastIndex, startIndex)));
            }

            // Add comment and the original text
            const currentCommentId = (++commentId).toString();
            comments.push({
                id: currentCommentId,
                author: "CorrigeAI",
                date: new Date(),
                children: [
                    new Paragraph({
                        children: [
                            new TextRun({ text: `Sugestão: "${correction.suggestedCorrection}"`, bold: true }),
                        ]
                    }),
                    new Paragraph({
                        children: [
                            new TextRun({ text: `Motivo: ${correction.reason}`, italics: true }),
                        ]
                    })
                ]
            });

            children.push(new CommentRangeStart(currentCommentId));
            children.push(new TextRun(correction.originalText));
            children.push(new CommentRangeEnd(currentCommentId));

            lastIndex = startIndex + correction.originalText.length;
        }

        // Add any remaining text in the paragraph
        if (lastIndex < pText.length) {
            children.push(new TextRun(pText.substring(lastIndex)));
        }

        paragraphs.push(new Paragraph({ children }));
    }

    const doc = new Document({
        comments: {
            children: comments,
        },
