/**
 * Creates a new .docx file with corrections inserted as comments.
 */
export async function createDocxWithComments(originalFile: File, corrections: Correction[]): Promise<Blob> {
    const { Packer, Document, Paragraph, TextRun, CommentRangeStart, CommentRangeEnd } = (window as any).docx;

    const arrayBuffer = await originalFile.arrayBuffer();
    // We need paragraphs to map corrections by index
    const textResult = await (window as any).mammoth.extractRawText({ arrayBuffer });
    const originalParagraphs = textResult.value.split('\n');

    const correctionsByParagraph: Map<number, Correction[]> = new Map();
    for (const correction of corrections) {
        if (!correctionsByParagraph.has(correction.paragraphIndex)) {
            correctionsByParagraph.set(correction.paragraphIndex, []);
        }
        correctionsByParagraph.get(correction.paragraphIndex)?.push(correction);
    }

    let commentId = 0;
    const comments: any[] = [];
    const paragraphs: any[] = [];

    for (let i = 0; i < originalParagraphs.length; i++) {
        const pText = originalParagraphs[i];
        const pCorrections = correctionsByParagraph.get(i) || [];

        if (pCorrections.length === 0) {
            paragraphs.push(new Paragraph({ children: [new TextRun(pText)] }));
            continue;
        }

        // Sort corrections by their appearance in the text to handle them in order
        pCorrections.sort((a, b) => pText.indexOf(a.originalText) - pText.indexOf(b.originalText));

        const children: any[] = [];
        let lastIndex = 0;

        for (const correction of pCorrections) {
            const startIndex = pText.indexOf(correction.originalText, lastIndex);

            if (startIndex === -1) {
                // Could not find the text, maybe Gemini hallucinated or text was slightly different
                console.warn(`Could not find originalText "${correction.originalText}" in paragraph ${i}. Skipping correction.`);
                continue;
            }

            // Add text before the correction
            if (startIndex > lastIndex) {
                children.push(new TextRun(pText.substring(lastIndex, startIndex)));
            }

            // Add comment and the original text
            const currentCommentId = (++commentId).toString();
            comments.push({
                id: currentCommentId,
                author: "CorrigeAI",
                date: new Date(),
                children: [
                    new Paragraph({
                        children: [
                            new TextRun({ text: `Sugestão: "${correction.suggestedCorrection}"`, bold: true }),
                        ]
                    }),
                    new Paragraph({
                        children: [
                            new TextRun({ text: `Motivo: ${correction.reason}`, italics: true }),
                        ]
                    })
                ]
            });

            children.push(new CommentRangeStart(currentCommentId));
            children.push(new TextRun(correction.originalText));
            children.push(new CommentRangeEnd(currentCommentId));

            lastIndex = startIndex + correction.originalText.length;
        }

        // Add any remaining text in the paragraph
        if (lastIndex < pText.length) {
            children.push(new TextRun(pText.substring(lastIndex)));
        }

        paragraphs.push(new Paragraph({ children }));
    }

    const doc = new Document({
        comments: {
            children: comments,
        },
        sections: [{
            children: paragraphs,
        }],
    });

    return Packer.toBlob(doc);
}

