import { Correction } from '../types';
import mammoth from 'mammoth';
import { Packer, Document, Paragraph, TextRun, CommentRangeStart, CommentRangeEnd } from 'docx';

/**
 * Extracts raw text content from a .docx file.
 * Each paragraph is an element in the returned string, separated by newlines.
 */
export async function extractTextFromDocx(file: File): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer });
  return result.value;
}

/**
 * Normalizes text for robust comparison by converting to lowercase, removing diacritics (accents),
 * and collapsing consecutive whitespace into a single space.
 * @param text The string to normalize.
 * @returns The normalized string.
 */
const normalize = (text: string): string => {
  if (!text) return '';
  return text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, ' ');
};

/**
 * Finds the start and end indices of a needle string within a haystack string using normalized matching.
 * This is more robust than a literal search.
 * @param haystack The string to search within.
 * @param needle The string to search for.
 * @returns An object with start and end indices, or null if not found.
 */
function findFuzzy(haystack: string, needle: string): { start: number, end: number } | null {
    const normalizedNeedle = normalize(needle);
    if (!normalizedNeedle.trim()) return null;

    // To optimize, we search for substrings of a similar length to the needle.
    const minLen = Math.max(1, Math.round(needle.length * 0.8));
    const maxLen = Math.round(needle.length * 1.2) + 5; // Extra buffer

    for (let i = 0; i <= haystack.length - minLen; i++) {
        for (let len = minLen; len <= maxLen && i + len <= haystack.length; len++) {
            const sub = haystack.substring(i, i + len);
            if (normalize(sub) === normalizedNeedle) {
                return { start: i, end: i + len };
            }
        }
    }
    return null;
}


/**
 * Creates a new .docx file with corrections inserted as comments.
 */
export async function createDocxWithComments(originalFile: File, corrections: Correction[]): Promise<Blob> {
    const arrayBuffer = await originalFile.arrayBuffer();
    const textResult = await mammoth.extractRawText({ arrayBuffer });
    const originalParagraphs = textResult.value.split('\n');

    const correctionsByParagraph: Map<number, Correction[]> = new Map();
    for (const correction of corrections) {
        if (!correctionsByParagraph.has(correction.paragraphIndex)) {
            correctionsByParagraph.set(correction.paragraphIndex, []);
        }
        correctionsByParagraph.get(correction.paragraphIndex)?.push(correction);
    }

    let commentIdCounter = 0;
    const comments: any[] = [];
    const paragraphs: Paragraph[] = [];

    for (let i = 0; i < originalParagraphs.length; i++) {
        let pText = originalParagraphs[i];
        const pCorrections = correctionsByParagraph.get(i) || [];
        const children: (TextRun | CommentRangeStart | CommentRangeEnd)[] = [];
        const unplacedCorrections: Correction[] = [];

        if (pCorrections.length === 0) {
            paragraphs.push(new Paragraph({ children: [new TextRun(pText)] }));
            continue;
        }

        // Attempt to find and sort corrections by their position in the paragraph
        const sortedCorrections = pCorrections
            .map(c => ({ correction: c, position: findFuzzy(pText, c.originalText) }))
            .sort((a, b) => (a.position?.start ?? Infinity) - (b.position?.start ?? Infinity));

        let lastIndex = 0;

        for (const { correction, position } of sortedCorrections) {
            if (position && position.start >= lastIndex) {
                // Add text before the correction
                if (position.start > lastIndex) {
                    children.push(new TextRun(pText.substring(lastIndex, position.start)));
                }

                // Add the comment and the original text wrapped in comment ranges
                commentIdCounter++;
                const commentId = commentIdCounter.toString();
                comments.push({
                    id: commentId,
                    author: "CorrigeAI",
                    date: new Date(),
                    children: [
                        new Paragraph({ children: [new TextRun({ text: `Sugestão: "${correction.suggestedCorrection}"`, bold: true })] }),
                        new Paragraph({ children: [new TextRun({ text: `Motivo: ${correction.reason}`, italics: true })] })
                    ]
                });

                children.push(new CommentRangeStart(commentId));
                children.push(new TextRun(pText.substring(position.start, position.end)));
                children.push(new CommentRangeEnd(commentId));

                lastIndex = position.end;
            } else {
                unplacedCorrections.push(correction);
            }
        }

        // Add any remaining text
        if (lastIndex < pText.length) {
            children.push(new TextRun(pText.substring(lastIndex)));
        }

        // **Fallback Mechanism**: Handle corrections that could not be placed
        for (const correction of unplacedCorrections) {
             commentIdCounter++;
             const commentId = commentIdCounter.toString();
             comments.push({
                id: commentId,
                author: "CorrigeAI",
                date: new Date(),
                children: [
                    new Paragraph({ children: [
                        new TextRun({ text: `Correção não localizada no texto.`, bold: true }),
                    ]}),
                    new Paragraph({ children: [
                        new TextRun({ text: `Trecho original: "${correction.originalText}"` }),
                    ]}),
                    new Paragraph({ children: [
                        new TextRun({ text: `Sugestão: "${correction.suggestedCorrection}"` }),
                    ]}),
                    new Paragraph({ children: [
                        new TextRun({ text: `Motivo: ${correction.reason}`, italics: true }),
                    ]})
                ]
            });
            // Anchor the comment at the beginning of the paragraph with an empty TextRun
            children.unshift(new CommentRangeStart(commentId), new TextRun(), new CommentRangeEnd(commentId));
        }

        paragraphs.push(new Paragraph({ children }));
    }

    const doc = new Document({
        comments: { children: comments },
        sections: [{ children: paragraphs }],
    });

    return Packer.toBlob(doc);
}

