    }

    let commentIdCounter = 0;
    const comments: any[] = [];
    const paragraphs: Paragraph[] = [];

    for (let i = 0; i < originalParagraphs.length; i++) {
        const pText = originalParagraphs[i];
        const pCorrections = correctionsByParagraph.get(i) || [];

        if (pCorrections.length === 0) {
            // No corrections, create a simple paragraph.
            paragraphs.push(new Paragraph({ children: [new TextRun(pText)] }));
            continue;
        }

        // --- Defensive Commenting Strategy ---
        // Apply all comments to the entire paragraph to avoid manipulating runs,
        // which is the main source of instability.

        const textRun = new TextRun(pText);
        const commentStarts: CommentRangeStart[] = [];
        const commentEnds: CommentRangeEnd[] = [];

        for (const correction of pCorrections) {
            commentIdCounter++;
            const commentId = commentIdCounter.toString();

            // Add the detailed comment content to the document's central comment list.
            // Since the anchor is not precise, the comment text must be explicit.
            comments.push({
                id: commentId,
                author: "CorrigeAI",
                date: new Date(),
                children: [
                    new Paragraph({ children: [
                        new TextRun({ text: `Referente ao trecho: "${correction.originalText}"`, italics: true }),
                    ]}),
                     new Paragraph({ children: [
                        new TextRun({ text: `Sugestão: "${correction.suggestedCorrection}"`, bold: true }),
                    ]}),
                     new Paragraph({ children: [
                        new TextRun({ text: `Motivo: ${correction.reason}` }),
                    ]})
                ]
            });

            // Prepare the start/end tags to wrap the entire paragraph's text run.
            commentStarts.push(new CommentRangeStart(commentId));
            // Prepend to a new array to get the reversed order for correct XML nesting (e.g., end2, end1).
            commentEnds.unshift(new CommentRangeEnd(commentId));
        }

        // Construct the paragraph's children array with comments wrapping the single TextRun.
        // This is the robust way to add multiple comments to the same block of text.
        // e.g., [start1, start2, textRun, end2, end1]
        const children = [...commentStarts, textRun, ...commentEnds];
        paragraphs.push(new Paragraph({ children }));
    }

    const doc = new Document({
        comments: { children: comments },
        sections: [{ children: paragraphs }],
    });

    return Packer.toBlob(doc);
}

import { Correction } from '../types';
import mammoth from 'mammoth';
import { Packer, Document, Paragraph, TextRun, CommentRangeStart, CommentRangeEnd } from 'docx';

/**
 * Extracts raw text content from a .docx file.
 * Each paragraph is an element in the returned string, separated by newlines.
 */
export async function extractTextFromDocx(file: File): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer });
  return result.value;
}

/**
 * Creates a new .docx file with corrections inserted as comments.
 * This function adopts a defensive strategy by applying comments at the paragraph level,
 * ensuring stability and preventing errors from complex document structures.
 */
export async function createDocxWithComments(originalFile: File, corrections: Correction[]): Promise<Blob> {
    const arrayBuffer = await originalFile.arrayBuffer();
    const textResult = await mammoth.extractRawText({ arrayBuffer });
    const originalParagraphs = textResult.value.split('\n');

    const correctionsByParagraph: Map<number, Correction[]> = new Map();
    for (const correction of corrections) {
        if (!correctionsByParagraph.has(correction.paragraphIndex)) {
            correctionsByParagraph.set(correction.paragraphIndex, []);
        }
        correctionsByParagraph.get(correction.paragraphIndex)?.push(correction);
    }

    let commentIdCounter = 0;
    const comments: any[] = [];
    const paragraphs: Paragraph[] = [];

    for (let i = 0; i < originalParagraphs.length; i++) {
        const pText = originalParagraphs[i];
        const pCorrections = correctionsByParagraph.get(i) || [];

        if (pCorrections.length === 0) {
            // No corrections, create a simple paragraph.
            paragraphs.push(new Paragraph({ children: [new TextRun(pText)] }));
            continue;
        }

        // --- Defensive Commenting Strategy ---
        // Apply all comments to the entire paragraph to avoid manipulating runs,
        // which is the main source of instability.

        const textRun = new TextRun(pText);
        const commentStarts: CommentRangeStart[] = [];
        const commentEnds: CommentRangeEnd[] = [];

        for (const correction of pCorrections) {
            commentIdCounter++;
            const commentId = commentIdCounter.toString();

            // Add the detailed comment content to the document's central comment list.
            // Since the anchor is not precise, the comment text must be explicit.
            comments.push({
                id: commentId,
                author: "CorrigeAI",
                date: new Date(),
                children: [
                    new Paragraph({ children: [
                        new TextRun({ text: `Referente ao trecho: "${correction.originalText}"`, italics: true }),
                    ]}),
                     new Paragraph({ children: [
                        new TextRun({ text: `Sugestão: "${correction.suggestedCorrection}"`, bold: true }),
                    ]}),
                     new Paragraph({ children: [
                        new TextRun({ text: `Motivo: ${correction.reason}` }),
                    ]})
                ]
            });

            // Prepare the start/end tags to wrap the entire paragraph's text run.
            commentStarts.push(new CommentRangeStart(commentId));
            // Prepend to a new array to get the reversed order for correct XML nesting (e.g., end2, end1).
            commentEnds.unshift(new CommentRangeEnd(commentId));
        }

        // Construct the paragraph's children array with comments wrapping the single TextRun.
        // This is the robust way to add multiple comments to the same block of text.
        // e.g., [start1, start2, textRun, end2, end1]
        const children = [...commentStarts, textRun, ...commentEnds];
        paragraphs.push(new Paragraph({ children }));
    }

    // --- MANDATORY VALIDATION CHECK ---
    // If corrections were identified by the AI, the final document MUST contain comments.
    // If the 'comments' array is empty at this stage, it means the creation process failed.
    if (corrections.length > 0 && comments.length === 0) {
      throw new Error("Não foi possível aplicar as correções como comentários. O documento não foi alterado.");
    }

    const doc = new Document({
        comments: { children: comments },
        sections: [{ children: paragraphs }],
    });

    return Packer.toBlob(doc);
}

import React, { useState, useCallback } from 'react';
import { Correction } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import FileUpload from './components/FileUpload';
import ProcessingView from './components/ProcessingView';
import ResultsView from './components/ResultsView';
import NoCorrectionsView from './components/NoCorrectionsView';
import { extractTextFromDocx } from './services/docxService';
import { getCorrections } from './services/geminiService';

type AppState = 'upload' | 'processing' | 'result' | 'error' | 'no-corrections';

export default function App() {
  const [appState, setAppState] = useState<AppState>('upload');
  const [error, setError] = useState<string | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);
  const [corrections, setCorrections] = useState<Correction[]>([]);

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setCorrections([]);

    try {
      const textContent = await extractTextFromDocx(file);
      if (!textContent.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      const foundCorrections: Correction[] = await getCorrections(textContent);

      if (foundCorrections.length === 0) {
        setAppState('no-corrections');
        return;
      }

      setCorrections(foundCorrections);
      setAppState('result');
    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, []);

  const handleReset = () => {
    setAppState('upload');
    setError(null);
    setOriginalFile(null);
    setCorrections([]);
  };

  const renderContent = () => {
    switch (appState) {
      case 'upload':
        return <FileUpload onProcess={handleFileProcess} />;
      case 'processing':
        return <ProcessingView />;
      case 'result':
        if (corrections.length === 0 || !originalFile) {
          handleReset();
          return null;
        }
        return <ResultsView corrections={corrections} fileName={originalFile.name} onReset={handleReset} />;
      case 'no-corrections':
        return <NoCorrectionsView onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-white rounded-lg shadow-lg">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-dark-blue text-white rounded-md hover:bg-brand-teal transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <FileUpload onProcess={handleFileProcess} />;
    }
  };

  return (
    <div className="min-h-screen bg-brand-gray flex flex-col">
      <Header />
      <main className="flex-grow container mx-auto px-4 py-8 flex items-center justify-center">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
}

