import mammoth from 'mammoth';

export interface ParagraphInfo {
  text: string;
  wordCount: number;
  startWordCount: number;
}

export interface ExtractedContent {
  fullText: string;
  paragraphs: ParagraphInfo[];
}

/**
 * Extracts raw text content from a .docx file and provides metadata for each paragraph.
 */
export async function extractTextFromDocx(file: File): Promise<ExtractedContent> {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer });

  const rawParagraphs = result.value.split('\n');
  const paragraphs: ParagraphInfo[] = [];
  let cumulativeWordCount = 0;

  for (const pText of rawParagraphs) {
    // A simple word count heuristic.
    const words = pText.trim().split(/\s+/).filter(Boolean);
    const wordCount = words.length;

    paragraphs.push({
      text: pText,
      wordCount: wordCount,
      startWordCount: cumulativeWordCount,
    });

    cumulativeWordCount += wordCount;
  }

  return {
    fullText: result.value,
    paragraphs: paragraphs,
  };
}

import React, { useState, useCallback } from 'react';
import { Correction } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import FileUpload from './components/FileUpload';
import ProcessingView from './components/ProcessingView';
import ResultsView from './components/ResultsView';
import NoCorrectionsView from './components/NoCorrectionsView';
import { extractTextFromDocx, ExtractedContent } from './services/docxService';
import { getCorrections } from './services/geminiService';

type AppState = 'upload' | 'processing' | 'result' | 'error' | 'no-corrections';

const WORDS_PER_PAGE = 250; // A reasonable estimate for standard documents

export default function App() {
  const [appState, setAppState] = useState<AppState>('upload');
  const [error, setError] = useState<string | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);
  const [corrections, setCorrections] = useState<Correction[]>([]);

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setCorrections([]);

    try {
      const { fullText, paragraphs }: ExtractedContent = await extractTextFromDocx(file);
      if (!fullText.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      const foundCorrections: Correction[] = await getCorrections(fullText);

      if (foundCorrections.length === 0) {
        setAppState('no-corrections');
        return;
      }

      const correctionsWithPageNumbers = foundCorrections.map(correction => {
        const paragraphIndex = correction.paragraphIndex;
        if (paragraphIndex >= 0 && paragraphIndex < paragraphs.length) {
          const paragraph = paragraphs[paragraphIndex];
          const estimatedPage = Math.floor(paragraph.startWordCount / WORDS_PER_PAGE) + 1;
          return { ...correction, estimatedPage };
        }
        return correction;
      });

      setCorrections(correctionsWithPageNumbers);
      setAppState('result');
    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, []);

  const handleReset = () => {
    setAppState('upload');
    setError(null);
    setOriginalFile(null);
    setCorrections([]);
  };

  const renderContent = () => {
    switch (appState) {
      case 'upload':
        return <FileUpload onProcess={handleFileProcess} />;
      case 'processing':
        return <ProcessingView />;
      case 'result':
        if (corrections.length === 0 || !originalFile) {
          handleReset();
          return null;
        }
        return <ResultsView corrections={corrections} fileName={originalFile.name} onReset={handleReset} />;
      case 'no-corrections':
        return <NoCorrectionsView onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-white rounded-lg shadow-lg">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-dark-blue text-white rounded-md hover:bg-brand-teal transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <FileUpload onProcess={handleFileProcess} />;
    }
  };

  return (
    <div className="min-h-screen bg-brand-gray flex flex-col">
      <Header />
      <main className="flex-grow container mx-auto px-4 py-8 flex items-center justify-center">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
}

