import { GoogleGenAI, Type } from "@google/genai";
import { Correction, GeminiCorrectionResponse, GeminiPedagogicalResponse } from '../types';
import { EDITORIAL_REVIEW_PROMPT, PEDAGOGICAL_REVIEW_PROMPT } from '../constants';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const correctionSchema = {
  type: Type.OBJECT,
  properties: {
    paragraphIndex: { type: Type.INTEGER, description: "O índice do parágrafo (baseado em 0) onde o erro foi encontrado." },
    originalSnippet: { type: Type.STRING, description: "O trecho exato do texto original que contém o erro. (Trecho Original)" },
    editorialAdjustment: { type: Type.STRING, description: "Descrição do ajuste editorial realizado. (Ajuste Editorial)" },
    revisedVersion: { type: Type.STRING, description: "A versão revisada e corrigida do trecho. (Versão Revisada)" },
  },
  required: ["paragraphIndex", "originalSnippet", "editorialAdjustment", "revisedVersion"]
};

const responseSchema = {
    type: Type.OBJECT,
    properties: {
        corrections: {
            type: Type.ARRAY,
            items: correctionSchema,
            description: "Uma lista de todas as correções encontradas no documento."
        }
    },
    required: ["corrections"]
}

const pedagogicalResponseSchema = {
    type: Type.OBJECT,
    properties: {
        detectedType: { type: Type.STRING, description: "O tipo de documento pedagógico detectado pela IA (e.g., 'TIPO A — ATIVIDADE CONTEXTUALIZADA')." },
        corrections: {
            type: Type.ARRAY,
            items: correctionSchema,
            description: "Uma lista de todas as correções encontradas no documento."
        }
    },
    required: ["detectedType", "corrections"]
}


export async function getCorrections(documentText: string): Promise<Correction[]> {
  const model = "gemini-3-pro-preview";

  try {
    const response = await ai.models.generateContent({
        model: model,
        contents: `Analise o seguinte texto e identifique os erros de acordo com as regras fornecidas:\n\n${documentText}`,
        config: {
            systemInstruction: EDITORIAL_REVIEW_PROMPT,
            responseMimeType: "application/json",
            responseSchema: responseSchema,
        }
    });

    const responseText = response.text;
    if (!responseText) {
        throw new Error("A resposta da IA estava vazia.");
    }

    const parsedResponse: GeminiCorrectionResponse = JSON.parse(responseText);

    if (!parsedResponse.corrections) {
      console.warn("A resposta da IA não continha o campo 'corrections'.", parsedResponse);
      return [];
    }

    return parsedResponse.corrections;

  } catch (error) {
    console.error("Erro ao chamar a API Gemini:", error);
    if (error instanceof Error && error.message.includes('API_KEY')) {
        throw new Error("A chave de API não é válida ou está faltando. Verifique suas configurações.");
    }
    throw new Error("Não foi possível obter as correções da IA.");
  }
}

export async function getPedagogicalCorrections(documentText: string): Promise<GeminiPedagogicalResponse> {
  const model = "gemini-3-pro-preview";

