import { GoogleGenAI, Type } from "@google/genai";
import { Correction, GeminiCorrectionResponse, GeminiPedagogicalResponse, GeminiPresentationResponse, PresentationCorrection, PedagogicalProcessingResult, GeminiPedagogicalValidationResponse } from '../types';
import { EDITORIAL_REVIEW_PROMPT, PEDAGOGICAL_REVIEW_PROMPT, PEDAGOGICAL_VALIDATION_PROMPT, PRESENTATIONS_REVIEW_PROMPT } from '../constants';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const correctionSchema = {
  type: Type.OBJECT,
  properties: {
    paragraphIndex: { type: Type.INTEGER, description: "O índice do parágrafo (baseado em 0). Usado para documentos textuais." },
    questionNumber: { type: Type.STRING, description: "O número/identificador da questão. Usado para Bancos de Questões." },
    originalSnippet: { type: Type.STRING, description: "O trecho exato do texto original que contém o erro. (Trecho Original)" },
    editorialAdjustment: { type: Type.STRING, description: "Descrição do ajuste editorial realizado. (Ajuste Editorial)" },
    revisedVersion: { type: Type.STRING, description: "A versão revisada e corrigida do trecho. (Versão Revisada)" },
  },
  required: ["originalSnippet", "editorialAdjustment", "revisedVersion"]
};

const presentationCorrectionSchema = {
  type: Type.OBJECT,
  properties: {
    slideNumber: { type: Type.INTEGER, description: "O número da cena (slide) onde o erro foi encontrado (base 1)." },
    originalSnippet: { type: Type.STRING, description: "O trecho exato do texto original que contém o erro." },
    editorialAdjustment: { type: Type.STRING, description: "Descrição do ajuste realizado." },
    revisedVersion: { type: Type.STRING, description: "A versão revisada e corrigida do trecho." },
  },
  required: ["slideNumber", "originalSnippet", "editorialAdjustment", "revisedVersion"]
};

const responseSchema = {
    type: Type.OBJECT,
    properties: {
        corrections: {
            type: Type.ARRAY,
            items: correctionSchema,
            description: "Uma lista de todas as correções encontradas no documento."
        }
    },
    required: ["corrections"]
}

const pedagogicalResponseSchema = {
    type: Type.OBJECT,
    properties: {
        detectedType: { type: Type.STRING, description: "O tipo de documento pedagógico detectado pela IA (e.g., 'TIPO A — ATIVIDADE CONTEXTUALIZADA')." },
        corrections: {
            type: Type.ARRAY,
            items: correctionSchema,
            description: "Uma lista de todas as correções encontradas no documento."
        }
    },
    required: ["detectedType", "corrections"]
}

const presentationResponseSchema = {
    type: Type.OBJECT,
    properties: {
        detectedType: { type: Type.STRING, description: "O tipo de apresentação detectado pela IA (e.g., 'TIPO P1 — APRESENTAÇÃO CONTEUDISTA / EXPLICATIVA')." },
        corrections: {
            type: Type.ARRAY,
            items: presentationCorrectionSchema,
            description: "Uma lista de todas as correções encontradas na apresentação."
        }
    },
    required: ["detectedType", "correções"]
}

const pedagogicalValidationSchema = {
  type: Type.OBJECT,
  properties: {
    validationStatus: { 
      type: Type.STRING, 
      description: "O status da validação. Deve ser 'STATUS_ERRO_CONCEITUAL_ENCONTRADO' ou 'STATUS_APTO_PARA_REVISAO_LINGUISTICA'."
    },
    pedagogicalErrors: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          questionNumber: { type: Type.STRING, description: "Número ou identificação da questão com erro." },
          errorType: { type: Type.STRING, description: "O tipo de erro pedagógico encontrado." },
          whatIsWrong: { type: Type.STRING, description: "Descrição objetiva do que está errado na questão." },
          whatShouldBeCorrected: { type: Type.STRING, description: "Ação corretiva clara e explícita que o operador deve tomar." },
        },
        required: ["questionNumber", "errorType", "whatIsWrong", "whatShouldBeCorrected"]
      },
      description: "Uma lista de erros pedagógicos encontrados. Vazio se o status for apto."
    }
  },
  required: ["validationStatus", "pedagogicalErrors"]
};


export async function getCorrections(documentText: string): Promise<Correction[]> {
  const model = "gemini-3-pro-preview";

  try {
    const response = await ai.models.generateContent({
        model: model,
        contents: `Analise o seguinte texto e identifique os erros de acordo com as regras fornecidas:\n\n${documentText}`,
        config: {
            systemInstruction: EDITORIAL_REVIEW_PROMPT,
            responseMimeType: "application/json",
            responseSchema: responseSchema,
        }
    });

    const responseText = response.text;
    if (!responseText) {
        throw new Error("A resposta da IA estava vazia.");
    }

    const parsedResponse: GeminiCorrectionResponse = JSON.parse(responseText);

    if (!parsedResponse.corrections) {
      console.warn("A resposta da IA não continha o campo 'corrections'.", parsedResponse);
      return [];
    }

    return parsedResponse.corrections;

  } catch (error) {
    console.error("Erro ao chamar a API Gemini:", error);
    if (error instanceof Error && error.message.includes('API_KEY')) {
        throw new Error("A chave de API não é válida ou está faltando. Verifique suas configurações.");
    }
    throw new Error("Não foi possível obter as correções da IA.");
  }
}

export async function getPedagogicalCorrections(documentText: string): Promise<PedagogicalProcessingResult> {
  const model = "gemini-3-pro-preview";

  try {
    // Etapa 1 & 2: Validar o documento conceitualmente e detectar o tipo
    const validationResponse = await ai.models.generateContent({
      model: model,
      contents: `Valide o seguinte documento educacional:\n\n${documentText}`,
      config: {
        systemInstruction: PEDAGOGICAL_VALIDATION_PROMPT,
        responseMimeType: "application/json",
        responseSchema: pedagogicalValidationSchema,
      }
    });

    const validationText = validationResponse.text;
    if (!validationText) {
      throw new Error("A resposta da validação pedagógica estava vazia.");
    }
    const parsedValidation: GeminiPedagogicalValidationResponse = JSON.parse(validationText);

    // Etapa 3: Verificar o status da validação. Se houver erros, bloquear e retornar.
    if (parsedValidation.validationStatus === 'STATUS_ERRO_CONCEITUAL_ENCONTRADO') {
      return {
        detectedType: 'Banco de Questões (com erros conceituais)',
        pedagogicalErrors: parsedValidation.pedagogicalErrors,
      };
    }

    // Etapa 4: Se apto para revisão, prosseguir com a correção linguística.
    if (parsedValidation.validationStatus === 'STATUS_APTO_PARA_REVISAO_LINGUISTICA') {
      const linguisticResponse = await ai.models.generateContent({
        model: model,
        contents: `Analise o seguinte texto e identifique os erros de acordo com as regras fornecidas:\n\n${documentText}`,
        config: {
            systemInstruction: PEDAGOGICAL_REVIEW_PROMPT,
            responseMimeType: "application/json",
            responseSchema: pedagogicalResponseSchema,
        }
      });

      const linguisticText = linguisticResponse.text;
      if (!linguisticText) {
          throw new Error("A resposta da revisão linguística estava vazia.");
      }

      const parsedLinguistic: GeminiPedagogicalResponse = JSON.parse(linguisticText);

      if (!parsedLinguistic.corrections || !parsedLinguistic.detectedType) {
        console.warn("A resposta da IA (linguística) não continha os campos 'corrections' ou 'detectedType'.", parsedLinguistic);
        throw new Error("A resposta da IA (linguística) está malformada.");
      }

      return {
        detectedType: parsedLinguistic.detectedType,
        linguisticCorrections: parsedLinguistic.corrections
      };
    }

    throw new Error("Status de validação desconhecido: " + parsedValidation.validationStatus);

  } catch (error) {
    console.error("Erro ao chamar a API Gemini no fluxo pedagógico:", error);
    if (error instanceof Error && error.message.includes('API_KEY')) {
        throw new Error("A chave de API não é válida ou está faltando. Verifique suas configurações.");
    }
    throw new Error("Não foi possível obter as correções da IA.");
  }
}

export async function getPresentationCorrections(documentText: string): Promise<GeminiPresentationResponse> {
  const model = "gemini-3-pro-preview";

  try {
    const response = await ai.models.generateContent({
        model: model,
        contents: `Analise o seguinte texto de apresentação e identifique os erros de acordo com as regras fornecidas:\n\n${documentText}`,
        config: {
            systemInstruction: PRESENTATIONS_REVIEW_PROMPT,
            responseMimeType: "application/json",
            responseSchema: presentationResponseSchema,
        }
    });

    const responseText = response.text;
    if (!responseText) {
        throw new Error("A resposta da IA estava vazia.");
    }

    const parsedResponse: GeminiPresentationResponse = JSON.parse(responseText);

    if (!parsedResponse.corrections || !parsedResponse.detectedType) {
      console.warn("A resposta da IA não continha os campos 'corrections' ou 'detectedType'.", parsedResponse);
      throw new Error("A resposta da IA está malformada.");
    }

    return parsedResponse;

  } catch (error) {
    console.error("Erro ao chamar a API Gemini:", error);
    if (error instanceof Error && error.message.includes('API_KEY')) {
        throw new Error("A chave de API não é válida ou está faltando. Verifique suas configurações.");
    }
    throw new Error("Não foi possível obter as correções da IA.");
  }
}

import React, { useState, useCallback } from 'react';
import { Correction } from '../types';
import FileUpload from './FileUpload';
import ProcessingView from './ProcessingView';
import ResultsView from './ResultsView';
import NoCorrectionsView from './NoCorrectionsView';
import { extractTextFromDocx } from '../services/docxService';
import { getCorrections } from '../services/geminiService';

type AppState = 'upload' | 'processing' | 'result' | 'error' | 'no-corrections';

interface EditorialDocsProps {
    onBack: () => void;
}

export default function EditorialDocs({ onBack }: EditorialDocsProps) {
  const [appState, setAppState] = useState<AppState>('upload');
  const [error, setError] = useState<string | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);
  const [corrections, setCorrections] = useState<Correction[]>([]);

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setCorrections([]);

    try {
      const textContent = await extractTextFromDocx(file);
      if (!textContent.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      const foundCorrections: Correction[] = await getCorrections(textContent);

      if (foundCorrections.length === 0) {
        setAppState('no-corrections');
        return;
      }

      setCorrections(foundCorrections);
      setAppState('result');
    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, []);

  const handleReset = () => {
    setAppState('upload');
    setError(null);
    setOriginalFile(null);
    setCorrections([]);
  };

  const renderContent = () => {
    switch (appState) {
      case 'upload':
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Ebook" />;
      case 'processing':
        return <ProcessingView />;
      case 'result':
        if (corrections.length === 0 || !originalFile) {
          handleReset();
          return null;
        }
        const rows = corrections.map(c => ({
            index: c.paragraphIndex !== undefined ? c.paragraphIndex + 1 : 'N/A',
            originalSnippet: c.originalSnippet,
            editorialAdjustment: c.editorialAdjustment,
            revisedVersion: c.revisedVersion
        }));
        return <ResultsView rows={rows} fileName={originalFile.name} onReset={handleReset} indexColumnHeader="Parágrafo" />;
      case 'no-corrections':
        return <NoCorrectionsView onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-brand-surface rounded-lg shadow-sm border border-red-200">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-primary text-white rounded-full hover:bg-brand-dark transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Ebook" />;
    }
  };

  return (
    <div className="w-full">
        <button onClick={onBack} className="mb-4 text-brand-primary hover:text-brand-dark font-medium transition-colors">
            &larr; Voltar para a seleção de módulos
        </button>
        {renderContent()}
    </div>
    );
}

import React, { useState, useCallback } from 'react';
import { Correction, PedagogicalError } from '../types';
import FileUpload from './FileUpload';
import ProcessingView from './ProcessingView';
import ResultsView from './ResultsView';
import NoCorrectionsView from './NoCorrectionsView';
import PedagogicalErrorsView from './PedagogicalErrorsView';
import { extractTextFromDocx } from '../services/docxService';
import { getPedagogicalCorrections } from '../services/geminiService';

type AppState = 'upload' | 'processing' | 'linguisticResult' | 'pedagogicalErrorResult' | 'error' | 'no-corrections';

interface PedagogicalDocsProps {
    onBack: () => void;
}

export default function PedagogicalDocs({ onBack }: PedagogicalDocsProps) {
  const [appState, setAppState] = useState<AppState>('upload');
  const [error, setError] = useState<string | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);
  const [linguisticCorrections, setLinguisticCorrections] = useState<Correction[]>([]);
  const [pedagogicalErrors, setPedagogicalErrors] = useState<PedagogicalError[]>([]);
  const [detectedType, setDetectedType] = useState<string>('');

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setLinguisticCorrections([]);
    setPedagogicalErrors([]);
    setDetectedType('');

    try {
      const textContent = await extractTextFromDocx(file);
      if (!textContent.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      const result = await getPedagogicalCorrections(textContent);

      setDetectedType(result.detectedType);

      if (result.pedagogicalErrors && result.pedagogicalErrors.length > 0) {
        setPedagogicalErrors(result.pedagogicalErrors);
        setAppState('pedagogicalErrorResult');
        return;
      }

      if (result.linguisticCorrections && result.linguisticCorrections.length > 0) {
        setLinguisticCorrections(result.linguisticCorrections);
        setAppState('linguisticResult');
        return;
      }

      setAppState('no-corrections');

    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, []);

  const handleReset = () => {
    setAppState('upload');
    setError(null);
    setOriginalFile(null);
    setLinguisticCorrections([]);
    setPedagogicalErrors([]);
    setDetectedType('');
  };

  const renderContent = () => {
    switch (appState) {
      case 'upload':
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Atividades Avaliativas" />;
      case 'processing':
        return <ProcessingView />;
      case 'linguisticResult':
        if (!originalFile) {
          handleReset();
          return null;
        }
        const isQuestionBank = detectedType.includes('BANCO DE QUESTÕES');
        const rows = linguisticCorrections.map(c => ({
            index: isQuestionBank 
                ? (c.questionNumber ?? 'N/A') 
                : (c.paragraphIndex !== undefined ? c.paragraphIndex + 1 : 'N/A'),
            originalSnippet: c.originalSnippet,
            editorialAdjustment: c.editorialAdjustment,
            revisedVersion: c.revisedVersion
        }));
        return <ResultsView 
            rows={rows} 
            fileName={originalFile.name} 
            onReset={handleReset} 
            detectedType={detectedType} 
            indexColumnHeader={isQuestionBank ? 'Questão' : 'Parágrafo'} 
        />;
      case 'pedagogicalErrorResult':
        if (!originalFile) {
          handleReset();
          return null;
        }
        return <PedagogicalErrorsView errors={pedagogicalErrors} fileName={originalFile.name} onReset={handleReset} />;
      case 'no-corrections':
        return <NoCorrectionsView onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-brand-surface rounded-lg shadow-sm border border-red-200">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-primary text-white rounded-full hover:bg-brand-dark transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Atividades Avaliativas" />;
    }
  };

  return (
    <div className="w-full">
        <button onClick={onBack} className="mb-4 text-brand-primary hover:text-brand-dark font-medium transition-colors">
            &larr; Voltar para a seleção de módulos
        </button>
        {renderContent()}
    </div>
    );
}

