        <p className="text-gray-500">Selecione o arquivo e o idioma de destino.</p>
      </div>

      <div className="mb-6">
        <label className="block text-sm font-medium text-gray-700 mb-2">Arquivo ({acceptedFileType})</label>
        <div 
            className="border-2 border-dashed rounded-lg p-8 text-center transition-colors cursor-pointer border-brand-border"
            onClick={() => fileInputRef.current?.click()}
        >
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept={acceptedFileType} className="hidden" />
            <p className="text-gray-500">{file ? file.name : `Clique para selecionar um arquivo ${acceptedFileType}`}</p>
        </div>
      </div>

      <div className="mb-8">
        <label htmlFor="language" className="block text-sm font-medium text-gray-700 mb-2">Traduzir para</label>
        <select
          id="language"
          value={language}
          onChange={(e) => setLanguage(e.target.value as TargetLanguage)}
          className="w-full p-2 border border-brand-border rounded-md shadow-sm focus:ring-brand-primary focus:border-brand-primary"
        >
          {Object.entries(languageMap).map(([code, name]) => (
            <option key={code} value={code}>{name}</option>
          ))}
        </select>
      </div>

      <div className="text-center">
        <button
          onClick={handleTranslate}
          disabled={!file}
          className="px-8 py-3 bg-brand-primary text-white font-bold rounded-full shadow-md disabled:bg-gray-400 hover:bg-brand-dark transition-colors"
        >
          Traduzir Documento
        </button>
      </div>
    </div>
  );

  const renderPreview = () => (
    <div className="w-full">
        <div className="bg-gray-100 p-4 rounded-lg shadow-sm border mb-4 flex justify-between items-center">
            <div>
                <h3 className="font-bold text-lg">Preview da Tradução</h3>
                <p className="text-sm text-gray-600">O texto é editável. Clique para corrigir.</p>
            </div>
            <div>
                 <button onClick={onBack} className="text-sm px-4 py-2 mr-2 bg-gray-200 text-gray-800 font-bold rounded-full shadow-sm hover:bg-gray-300 transition-colors">Voltar</button>
                <button onClick={handleDownload} disabled={state === 'generating'} className="px-6 py-2 bg-brand-primary text-white font-bold rounded-full shadow-md disabled:bg-gray-400 hover:bg-brand-dark transition-colors">
                    {state === 'generating' ? 'Gerando...' : 'Download'}
                </button>
            </div>
        </div>
        <div ref={previewRef} className="bg-white p-8 shadow-lg border rounded-md max-h-[70vh] overflow-y-auto">
            {documentPages.map(page => (
                <div key={page.pageNumber} className="mb-8 border-b-2 border-dashed pb-4 border-gray-200" style={{ pageBreakAfter: 'always' }}>
                    {page.blocks.map(block => {
                        const Tag = ['h1', 'h2', 'h3', 'p'].includes(block.type) ? block.type : 'p';
                        const isListItem = block.type === 'li';
                        return isListItem ? (
                            <li key={block.id} contentEditable onBlur={e => block.translatedText = e.currentTarget.textContent || ''} className="ml-8 list-disc py-1">{block.translatedText}</li>
                        ) : (
                            <Tag key={block.id} contentEditable onBlur={e => block.translatedText = e.currentTarget.textContent || ''} className="py-1">{block.translatedText}</Tag>
                        );
                    })}
                    <div className="text-center text-xs text-gray-400 mt-4">- {page.pageNumber} -</div>
                </div>
            ))}
        </div>
    </div>
  );

  if (state === 'preview' || state === 'generating') {
    return renderPreview();
  }

  if (state === 'parsing' || state === 'translating') {
    return <ProcessingView />;
  }

  return renderIdle();
}

import { GoogleGenAI, Type } from "@google/genai";
import { extractTextFromPptx } from './pptxService';
import { extractPagesAsImages } from './pdfService';
import { DocumentPage, StructuralBlock } from '../types';
import { DOCUMENT_STRUCTURE_PROMPT, BLOCK_TRANSLATE_PROMPT } from '../constants';

const API_KEY = process.env.API_KEY;
if (!API_KEY) throw new Error("API_KEY not set");

const ai = new GoogleGenAI({ apiKey: API_KEY });

const structureSchema = {
  type: Type.OBJECT,
  properties: {
    blocks: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING },
          content: { type: Type.STRING },
        },
        required: ["type", "content"],
      },
    },
  },
  required: ["blocks"],
};

async function getStructureFromImage(imageDataUrl: string): Promise<any> {
    const model = 'gemini-3-pro-image-preview';
    const imagePart = {
        inlineData: {
            mimeType: 'image/png',
            data: imageDataUrl.split(',')[1],
        },
    };

    try {
        const response = await ai.models.generateContent({
            model,
            contents: { parts: [imagePart] },
            config: {
                systemInstruction: DOCUMENT_STRUCTURE_PROMPT,
                responseMimeType: "application/json",
                responseSchema: structureSchema,
            },
        });

        const text = response.text.trim();
        return JSON.parse(text);

    } catch (error) {
        console.error("Error analyzing image structure:", error);
        throw new Error("Failed to analyze document structure with AI.");
    }
}


export async function processPdf(file: File): Promise<DocumentPage[]> {
  const pageImages = await extractPagesAsImages(file);
  const documentPages: DocumentPage[] = [];

  for (let i = 0; i < pageImages.length; i++) {
    const imageDataUrl = pageImages[i];
    const structuredContent = await getStructureFromImage(imageDataUrl);

    const blocks: StructuralBlock[] = structuredContent.blocks.map((block: any, index: number) => ({
      id: `page-${i + 1}-block-${index}`,
      type: ['h1', 'h2', 'h3', 'p', 'li'].includes(block.type) ? block.type : 'p',
      originalText: block.content,
      translatedText: '',
    }));

    documentPages.push({
      pageNumber: i + 1,
      blocks,
    });
  }

  return documentPages;
}


export async function processPptx(file: File): Promise<DocumentPage[]> {
  const slideTexts = await extractTextFromPptx(file);
  return slideTexts.map((slideText, index) => {
    const blocks: StructuralBlock[] = slideText.split('\n').filter(t => t.trim() !== '').map((text, blockIndex) => ({
      id: `page-${index + 1}-block-${blockIndex}`,
      type: 'p', // Simplified for PPTX, as structure is less defined
      originalText: text,
      translatedText: '',
    }));

    return {
      pageNumber: index + 1,
      blocks,
    };
  });
}

import * as pdfjsLib from 'pdfjs-dist';

// Set worker source for pdf.js
// This is necessary for the library to work correctly in a web environment.
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.5.136/build/pdf.worker.min.mjs`;

/**
 * Renders each page of a PDF file into a canvas and extracts it as a PNG image data URL.
 * @param file The PDF file.
 * @returns A promise that resolves to an array of base64 encoded PNG image strings.
 */
export async function extractPagesAsImages(file: File): Promise<string[]> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;
  const pageImageUrls: string[] = [];
  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d');

  if (!context) {
    throw new Error('Could not create canvas context');
  }

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 1.5 }); // Use a higher scale for better resolution
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    const renderContext = {
      canvasContext: context,
      viewport: viewport,
    };
    await page.render(renderContext).promise;

    pageImageUrls.push(canvas.toDataURL('image/png'));
  }

  canvas.remove();
  return pageImageUrls;
}

import PptxGenJS from 'pptxgenjs';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';
import { DocumentPage } from '../types';

/**
 * Generates a new .pptx file from the translated document pages.
 * @param pages The array of translated DocumentPage objects.
 * @param originalFileName The original file name to use for the new file.
 */
export async function generatePptx(pages: DocumentPage[], originalFileName: string) {
  const pptx = new PptxGenJS();

  pages.forEach(page => {
    const slide = pptx.addSlide();
    const textContent = page.blocks.map(block => block.translatedText).join('\n');
    // Add a single text box with all content. This is a simplification.
    // A more advanced version would handle positions and styles.
    slide.addText(textContent, { x: 0.5, y: 0.5, w: '90%', h: '90%' });
  });

  const newFileName = originalFileName.replace('.pptx', '_translated.pptx');
  pptx.writeFile({ fileName: newFileName });
}

/**
 * Generates a .pdf file from an HTML element.
 * @param element The HTML element containing the preview to be converted.
 * @param originalFileName The original file name to use for the new file.
 */
export async function generatePdf(element: HTMLElement, originalFileName: string) {
  const canvas = await html2canvas(element, { scale: 2 }); // Higher scale for better quality
  const imgData = canvas.toDataURL('image/png');

  const pdf = new jsPDF({
    orientation: 'portrait',
    unit: 'px',
    format: [canvas.width, canvas.height]
  });

  pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);

  const newFileName = originalFileName.replace('.pdf', '_translated.pdf');
  pdf.save(newFileName);
}

import React, { useState, useCallback } from 'react';
import { Correction } from '../types';
import FileUpload from './FileUpload';
import ProcessingView from './ProcessingView';
import ResultsView from './ResultsView';
import NoCorrectionsView from './NoCorrectionsView';
import { extractTextFromDocx } from '../services/docxService';
import { getCorrections } from '../services/geminiService';

type AppState = 'upload' | 'processing' | 'result' | 'error' | 'no-corrections';

interface EditorialDocsProps {
    onBack: () => void;
}

export default function EditorialDocs({ onBack }: EditorialDocsProps) {
  const [appState, setAppState] = useState<AppState>('upload');
  const [error, setError] = useState<string | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);
  const [corrections, setCorrections] = useState<Correction[]>([]);

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setCorrections([]);

    try {
      const textContent = await extractTextFromDocx(file);
      if (!textContent.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      const foundCorrections: Correction[] = await getCorrections(textContent);

      if (foundCorrections.length === 0) {
        setAppState('no-corrections');
        return;
      }

      setCorrections(foundCorrections);
      setAppState('result');
    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, []);

  const handleReset = () => {
    setAppState('upload');
    setError(null);
    setOriginalFile(null);
    setCorrections([]);
  };

  const renderContent = () => {
    switch (appState) {
      case 'upload':
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Ebook" />;
      case 'processing':
        return <ProcessingView />;
      case 'result':
        if (corrections.length === 0 || !originalFile) {
          handleReset();
          return null;
        }
        const rows = corrections.map(c => ({
            index: c.paragraphIndex !== undefined ? c.paragraphIndex + 1 : 'N/A',
            originalSnippet: c.originalSnippet,
            editorialAdjustment: c.editorialAdjustment,
            revisedVersion: c.revisedVersion
        }));
        return <ResultsView rows={rows} fileName={originalFile.name} onReset={handleReset} indexColumnHeader="Parágrafo" />;
      case 'no-corrections':
        return <NoCorrectionsView onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-brand-surface rounded-lg shadow-sm border border-red-200">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-primary text-white rounded-full hover:bg-brand-dark transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Ebook" />;
    }
  };

  return (
    <div className="w-full">
        <button onClick={onBack} className="mb-4 text-brand-primary hover:text-brand-dark font-medium transition-colors">
            &larr; Voltar
        </button>
        {renderContent()}
    </div>
    );
}

import React, { useState, useCallback } from 'react';
import { Correction, PedagogicalError } from '../types';
import FileUpload from './FileUpload';
import ProcessingView from './ProcessingView';
import ResultsView from './ResultsView';
import NoCorrectionsView from './NoCorrectionsView';
import PedagogicalErrorsView from './PedagogicalErrorsView';
import { extractTextFromDocx } from '../services/docxService';
import { getPedagogicalCorrections } from '../services/geminiService';

type AppState = 'upload' | 'processing' | 'linguisticResult' | 'pedagogicalErrorResult' | 'error' | 'no-corrections';

interface PedagogicalDocsProps {
    onBack: () => void;
}

export default function PedagogicalDocs({ onBack }: PedagogicalDocsProps) {
  const [appState, setAppState] = useState<AppState>('upload');
  const [error, setError] = useState<string | null>(null);
  const [originalFile, setOriginalFile] = useState<File | null>(null);
  const [linguisticCorrections, setLinguisticCorrections] = useState<Correction[]>([]);
  const [pedagogicalErrors, setPedagogicalErrors] = useState<PedagogicalError[]>([]);
  const [detectedType, setDetectedType] = useState<string>('');

  const handleFileProcess = useCallback(async (file: File) => {
    setAppState('processing');
    setOriginalFile(file);
    setError(null);
    setLinguisticCorrections([]);
    setPedagogicalErrors([]);
    setDetectedType('');

    try {
      const textContent = await extractTextFromDocx(file);
      if (!textContent.trim()) {
        throw new Error("O documento parece estar vazio. Por favor, verifique o arquivo e tente novamente.");
      }

      const result = await getPedagogicalCorrections(textContent);

      setDetectedType(result.detectedType);

      if (result.pedagogicalErrors && result.pedagogicalErrors.length > 0) {
        setPedagogicalErrors(result.pedagogicalErrors);
        setAppState('pedagogicalErrorResult');
        return;
      }

      if (result.linguisticCorrections && result.linguisticCorrections.length > 0) {
        setLinguisticCorrections(result.linguisticCorrections);
        setAppState('linguisticResult');
        return;
      }

      setAppState('no-corrections');

    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : 'Ocorreu um erro desconhecido.';
      setError(`Falha no processamento: ${errorMessage}. Por favor, tente novamente.`);
      setAppState('error');
    }
  }, []);

  const handleReset = () => {
    setAppState('upload');
    setError(null);
    setOriginalFile(null);
    setLinguisticCorrections([]);
    setPedagogicalErrors([]);
    setDetectedType('');
  };

  const renderContent = () => {
    switch (appState) {
      case 'upload':
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Atividades Avaliativas" />;
      case 'processing':
        return <ProcessingView />;
      case 'linguisticResult':
        if (!originalFile) {
          handleReset();
          return null;
        }
        const isQuestionBank = detectedType.includes('BANCO DE QUESTÕES');
        const rows = linguisticCorrections.map(c => ({
            index: isQuestionBank 
                ? (c.questionNumber ?? 'N/A') 
                : (c.paragraphIndex !== undefined ? c.paragraphIndex + 1 : 'N/A'),
            originalSnippet: c.originalSnippet,
            editorialAdjustment: c.editorialAdjustment,
            revisedVersion: c.revisedVersion
        }));
        return <ResultsView 
            rows={rows} 
            fileName={originalFile.name} 
            onReset={handleReset} 
            detectedType={detectedType} 
            indexColumnHeader={isQuestionBank ? 'Questão' : 'Parágrafo'} 
            pedagogicalValidationPassed={isQuestionBank}
        />;
      case 'pedagogicalErrorResult':
        if (!originalFile) {
          handleReset();
          return null;
        }
        return <PedagogicalErrorsView errors={pedagogicalErrors} fileName={originalFile.name} onReset={handleReset} />;
      case 'no-corrections':
        return <NoCorrectionsView onReset={handleReset} />;
      case 'error':
        return (
          <div className="text-center p-8 bg-brand-surface rounded-lg shadow-sm border border-red-200">
            <h2 className="text-2xl font-bold text-red-600 mb-4">Erro!</h2>
            <p className="text-gray-700 mb-6">{error}</p>
            <button
              onClick={handleReset}
              className="px-6 py-2 bg-brand-primary text-white rounded-full hover:bg-brand-dark transition-colors"
            >
              Tentar Novamente
            </button>
          </div>
        );
      default:
        return <FileUpload onProcess={handleFileProcess} fileType=".docx" title="Revisão de Atividades Avaliativas" />;
    }
  };

  return (
    <div className="w-full">
        <button onClick={onBack} className="mb-4 text-brand-primary hover:text-brand-dark font-medium transition-colors">
            &larr; Voltar
        </button>
        {renderContent()}
    </div>
    );
}

