const presentationResponseSchema = {
    type: Type.OBJECT,
    properties: {
        detectedType: { type: Type.STRING, description: "O tipo de apresentação detectado pela IA (e.g., 'TIPO P1 — APRESENTAÇÃO CONTEUDISTA / EXPLICATIVA')." },
        corrections: {
            type: Type.ARRAY,
            items: presentationCorrectionSchema,
            description: "Uma lista de todas as correções encontradas na apresentação."
        }
