export async function translateBlock(block: StructuralBlock, languageCode: TargetLanguage, languageName: string): Promise<string> {
    if (!block.originalText.trim()) {
        return "";
    }
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = BLOCK_TRANSLATE_PROMPT
        .replace('{LANGUAGE_NAME}', languageName)
        .replace('{LANGUAGE_CODE}', languageCode)
        .replace('{BLOCK_TYPE}', block.type)
        .replace('{TEXT_CONTENT}', block.originalText);

    let retries = 3;
    let delay = 2000; // Start with a 2-second delay

    while (retries > 0) {
        try {
            const response = await ai.models.generateContent({
                model,
                contents: prompt,
            });
            return response.text;
        } catch(error) {
            console.error(`Error translating block ID ${block.id}:`, error);
            const errorString = JSON.stringify(error); // Stringify to safely inspect

            // Check for rate limit error and if retries are available
            if ((errorString.includes('429') || errorString.includes('RESOURCE_EXHAUSTED')) && retries > 1) {
                console.warn(`Rate limit hit for block ${block.id}. Retrying in ${delay / 1000}s... (${retries - 1} retries left)`);
                await new Promise(resolve => setTimeout(resolve, delay));
                delay *= 2; // Exponential backoff
                retries--;
            } else {
                // For other errors or if retries are exhausted, re-throw.
                throw error;
            }
        }
    }

    // This part should ideally not be reached, but serves as a fallback.
    throw new Error(`Failed to translate block ${block.id} after multiple retries due to persistent rate limiting.`);
}


export async function processPdf(file: File): Promise<DocumentPage[]> {
  const pageTexts = await extractTextFromPdf(file);
  const documentPages: DocumentPage[] = [];

  for (let i = 0; i < pageTexts.length; i++) {
    const pageText = pageTexts[i];
    const blocks = inferStructureFromText(pageText, i + 1);

    documentPages.push({
      pageNumber: i + 1,
      blocks,
    });
  }

  return documentPages;
}


