import { extractTextFromDocx } from './docxService';

export interface PedagogicalMemory {
  sourceFileName: string;
  extractedContentLength: number;
  analyzedAt: Date;
  // Future fields for pedagogical rules will go here
}

export async function analyzeEbookAndCreateMemory(file: File): Promise<PedagogicalMemory> {
  // 1. Extract Text
  const textContent = await extractTextFromDocx(file);

  if (!textContent.trim()) {
    throw new Error("O Ebook parece estar vazio ou não pôde ser lido.");
  }

  // 2. Simulate Analysis (Phase 1: Structure Check)
  // In the future, this will call the AI to extract concepts, learning objectives, etc.
  await new Promise(resolve => setTimeout(resolve, 1500)); // Simulating processing time

  // 3. Create Memory Object
  const memory: PedagogicalMemory = {
    sourceFileName: file.name,
    extractedContentLength: textContent.length,
    analyzedAt: new Date(),
  };

  return memory;
}

