import { GoogleGenAI, Type } from "@google/genai";
import { extractTextFromDocx } from './docxService';
import { EDUCATIONAL_DESIGN_EBOOK_PROMPT } from '../constants';
import { EducationalDesignResult, PedagogicalMemory, PedagogicalReport } from '../types';

const API_KEY = process.env.API_KEY;
if (!API_KEY) {
  throw new Error("A chave de API não foi configurada. Por favor, configure a variável de ambiente API_KEY.");
}

// Schema definitions for the Gemini API
const pedagogicalMemorySchema = {
    type: Type.OBJECT,
    properties: {
        title: { type: Type.STRING },
        identifiedCatalog: { type: Type.STRING, enum: ['Qualisuper', 'Qualipós', 'Indefinido'] },
        chapters: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    chapterTitle: { type: Type.STRING },
                    centralThemes: { type: Type.ARRAY, items: { type: Type.STRING } },
                    keyConcepts: { type: Type.ARRAY, items: { type: Type.STRING } },
                    inferredLearningObjectives: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
        },
        globalAssessment: {
            type: Type.OBJECT,
            properties: {
                didacticProgression: { type: Type.STRING, enum: ['adequada', 'irregular'] },
                predominantCognitiveLevel: { type: Type.STRING, enum: ['compreensão', 'aplicação', 'análise', 'síntese'] },
                conceptualDensity: { type: Type.STRING, enum: ['baixa', 'média', 'alta'] }
            }
        }
    }
};

const pedagogicalReportSchema = {
    type: Type.OBJECT,
    properties: {
        statusGeral: { type: Type.STRING, enum: ['NaoPrecisaDeAjuste', 'AjustesNecessarios'] },
        strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
        adjustments: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    chapter: { type: Type.STRING },
                    subchapter: { type: Type.STRING },
                    paragraphReference: { type: Type.NUMBER },
                    problemIdentified: { type: Type.STRING },
                    educationalJustification: { type: Type.STRING },
                    suggestionForAdjustment: { type: Type.STRING },
                    gravity: { type: Type.STRING, enum: ['Baixa', 'Média', 'Alta'] }
                },
                required: ['chapter', 'paragraphReference', 'problemIdentified', 'educationalJustification', 'suggestionForAdjustment', 'gravity']
            }
        }
    }
};

const fullResponseSchema = {
    type: Type.OBJECT,
    properties: {
        memory: pedagogicalMemorySchema,
        report: pedagogicalReportSchema
    },
    required: ['memory', 'report']
};


export async function analyzeEbookAndCreateMemory(file: File): Promise<EducationalDesignResult> {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const model = "gemini-3-pro-preview"; // Using Pro model for complex analysis

  // 1. Extract Text
  const textContent = await extractTextFromDocx(file);

  if (!textContent.trim()) {
    throw new Error("O Ebook parece estar vazio ou não pôde ser lido.");
  }

  try {
      // 2. Call Gemini API
      const response = await ai.models.generateContent({
          model: model,
          contents: `Analise o seguinte texto de Ebook Educacional:\n\n${textContent.substring(0, 80000)}`, // Limiting chars just in case, though 3-pro handles large context.
          config: {
              systemInstruction: EDUCATIONAL_DESIGN_EBOOK_PROMPT,
              responseMimeType: "application/json",
              responseSchema: fullResponseSchema,
          }
      });

      const responseText = response.text;
      if (!responseText) {
          throw new Error("A IA não retornou nenhuma resposta.");
      }

      const parsedResponse = JSON.parse(responseText);

      // 3. Construct Final Objects
      const memory: PedagogicalMemory = {
          ...parsedResponse.memory,
          ebookId: crypto.randomUUID(),
          analyzedAt: new Date(),
          sourceFileName: file.name
      };

      const report: PedagogicalReport = parsedResponse.report;

      return { memory, report };

  } catch (error) {
      console.error("Erro na análise de Design Educacional:", error);
      throw new Error("Falha ao analisar o Ebook. Verifique se o arquivo é válido e tente novamente.");
  }
}

